import pandas as pd

# This script processes the output from the Redrob Resume Ranker.
# It reads the ranked candidates and highlights the top matches 
# for the Deloitte Full Stack Developer role.

def analyze_redrob_results(file_path):
    print("🚀 Starting Redrob Resume Ranker Analysis...")
    
    # Load the Excel file generated by Redrob
    df = pd.read_excel(file_path)
    
    # Display the Top 3 Candidates
    print("\n🏆 TOP 3 CANDIDATES FOR DELOITTE FULL STACK ROLE:")
    print("="*50)
    top_3 = df.head(3)
    for index, row in top_3.iterrows():
        print(f"Rank {row['Rank']}: {row['Resume']}")
        print(f"  - Score: {row['Candidate score']}")
        print(f"  - Passport Tier: {row['Redrob Passport Score']}")
        print("-" * 50)

    # Calculate average score
    avg_score = df['Candidate score'].mean()
    print(f"\n Average Candidate Score: {avg_score:.2f}")
    print(f"✅ Total Candidates Processed: {len(df)}")

if __name__ == "__main__":
    # This is the file we generated using the Redrob Platform
    analyze_redrob_results('Ranked 10 candidates.xlsx')
